+   /**
+    * Sanitize a path from a zip entry to prevent path traversal attacks.
+    * 
+    * @param path the path from a zip entry
+    * @return sanitized path
+    */
+   private static String sanitizePath(String path) {
+      if (path == null || path.isEmpty()) {
+         return path;
+      }
+      
+      // Normalize path separators
+      String normalized = path.replace('\\', '/');
+      
+      // Remove any leading slashes or directory traversal attempts
+      while (normalized.startsWith("/") || normalized.startsWith("./") || normalized.startsWith("../")) {
+         normalized = normalized.replaceFirst("^\\.\\.?/", "").replaceFirst("^/", "");
+      }
+      
+      // Remove any remaining directory traversal sequences
+      normalized = normalized.replaceAll("/\\.\\./", "/").replaceAll("/\\.\\.$", "");
+      return normalized.replaceAll("/\\./", "/");
+   }
 }

