+/**
+ * Sanitize SVG string by removing script elements and event handlers
+ * @param {string} svgString - The SVG string to sanitize
+ * @return {string} Sanitized SVG string
+ */
+function sanitizeSVG(svgString) {
+    // Remove <script> elements and their contents
+    let sanitized = svgString.replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, '');
+    // Remove event handlers (onload, onclick, etc.)
+    sanitized = sanitized.replace(/on\w+\s*=\s*["'][\s\S]*?["']/gi, '');
+    // Remove other dangerous attributes like href with javascript:
+    sanitized = sanitized.replace(/href\s*=\s*["']javascript:[\s\S]*?["']/gi, '');
+    return sanitized;
+}
